// In handlePollTick, replace the keyword check with address-aware check:

if newCommits != "" {
    pullCmd := exec.Command("git", "-C", cfg.RepoRoot, "pull", "--rebase", "origin", "main")
    pullCmd.CombinedOutput()

    // Check if new commits contain files addressed to THIS agent
    // Pattern: from-{other}-*.json OR to-{this-agent}-*.json
    diffCmd := exec.Command("git", "-C", cfg.RepoRoot, "diff",
        "--name-only", "HEAD~5..HEAD", "--", "transport/sessions/")
    diffOut, _ := diffCmd.Output()
    changedFiles := string(diffOut)

    // Only escalate if files are addressed to us or from someone else
    myPrefix := fmt.Sprintf("to-%s-", cfg.AgentID)
    fromOther := false
    for _, line := range strings.Split(changedFiles, "\n") {
        fname := filepath.Base(line)
        if strings.HasPrefix(fname, "from-") && !strings.HasPrefix(fname, "from-" + cfg.AgentID) {
            fromOther = true
            break
        }
        if strings.Contains(fname, myPrefix) {
            fromOther = true
            break
        }
    }

    if fromOther {
        logger.Info("Gc: new transport files addressed to us — delegating to Gf",
            "files", changedFiles)
        return false
    }

    logger.Info("Gc: new commits but no transport files addressed to us — handled")
    // Fall through to PR check
}
